import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"发布说明: 版本演进 | Antigravity-Manager","description":"了解 Antigravity-Manager 的版本演进方法。在 Settings 页确认版本并检查更新，通过 README Changelog 查看修复与提醒，用 /healthz 验证升级后可用性。","frontmatter":{"title":"发布说明: 版本演进 | Antigravity-Manager","sidebarTitle":"3 分钟看懂版本更新","subtitle":"版本演进：以 README 内嵌 Changelog 为准","description":"了解 Antigravity-Manager 的版本演进方法。在 Settings 页确认版本并检查更新，通过 README Changelog 查看修复与提醒，用 /healthz 验证升级后可用性。","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),n={name:"zh/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function l(i,t,d,s,g,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="版本演进-以-readme-内嵌-changelog-为准" tabindex="-1">版本演进：以 README 内嵌 Changelog 为准 <a class="header-anchor" href="#版本演进-以-readme-内嵌-changelog-为准" aria-label="Permalink to &quot;版本演进：以 README 内嵌 Changelog 为准&quot;">​</a></h1><p>你准备升级 Antigravity Tools，最怕的不是“没更新到”，而是“更新了才发现有兼容性变化”。这页把 <strong>Antigravity Tools Changelog（版本演进）</strong> 的阅读方法讲清楚，让你能在升级前就判断：这次更新会影响你什么。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>在 Settings 的 About 页快速确认当前版本、检查更新并拿到下载入口</li><li>在 README 的 Changelog 里只读对你有影响的版本段落（而不是从头翻到尾）</li><li>升级前先做一件事：确认是否有“需要你手动改配置/改模型映射”的提醒</li><li>升级后跑一遍最小验证（<code>/healthz</code>）确认代理还能用</li></ul><h2 id="什么是-changelog" tabindex="-1">什么是 Changelog？ <a class="header-anchor" href="#什么是-changelog" aria-label="Permalink to &quot;什么是 Changelog？&quot;">​</a></h2><p><strong>Changelog</strong> 是按版本记录“这次改了什么”的清单。Antigravity Tools 把它直接写在 README 的“版本演进”里，每个版本都会标出日期与关键变更。升级前先看 Changelog，能减少踩到兼容性变化或回归问题的概率。</p><h2 id="什么时候用这一页" tabindex="-1">什么时候用这一页 <a class="header-anchor" href="#什么时候用这一页" aria-label="Permalink to &quot;什么时候用这一页&quot;">​</a></h2><ul><li>你准备从旧版本升级到新版本，想先确认风险点</li><li>你遇到某个问题（比如 429/0 Token/Cloudflared），想确认它是否在近期版本被修复</li><li>你在团队里维护统一版本，需要给同事一个“按版本读变化”的方法</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">建议先把升级路径准备好</p><p>安装/升级方式很多（brew、Releases 手动下载、应用内更新）。如果你还没确定自己用哪条路，先看 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/start/installation/">安装与升级：桌面端最佳安装路径（brew / releases）</a></strong>。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-在-about-页确认你正在用的版本" tabindex="-1">第 1 步：在 About 页确认你正在用的版本 <a class="header-anchor" href="#第-1-步-在-about-页确认你正在用的版本" aria-label="Permalink to &quot;第 1 步：在 About 页确认你正在用的版本&quot;">​</a></h3><p><strong>为什么</strong> Changelog 是按版本组织的。你先知道自己当前版本，才知道“要从哪里开始看”。</p><p>操作路径：<strong>Settings</strong> → <strong>About</strong>。</p><p><strong>你应该看到</strong>：页面标题区显示应用名与版本号（例如 <code>v3.3.49</code>）。</p><h3 id="第-2-步-点-检查更新-拿到最新版本与下载入口" tabindex="-1">第 2 步：点“检查更新”，拿到最新版本与下载入口 <a class="header-anchor" href="#第-2-步-点-检查更新-拿到最新版本与下载入口" aria-label="Permalink to &quot;第 2 步：点“检查更新”，拿到最新版本与下载入口&quot;">​</a></h3><p><strong>为什么</strong> 你需要先知道“最新版本号是什么”，再去 Changelog 里挑出中间跨过的版本段落。</p><p>在 About 页点击“检查更新”。</p><p><strong>你应该看到</strong>：</p><ul><li>若有更新：提示“new version available”，并出现一个下载按钮（打开 <code>download_url</code>）</li><li>若已是最新：提示“latest version”</li></ul><h3 id="第-3-步-去-readme-的-changelog-只看你跨过的版本" tabindex="-1">第 3 步：去 README 的 Changelog 只看你跨过的版本 <a class="header-anchor" href="#第-3-步-去-readme-的-changelog-只看你跨过的版本" aria-label="Permalink to &quot;第 3 步：去 README 的 Changelog 只看你跨过的版本&quot;">​</a></h3><p><strong>为什么</strong> 你只需要关心“从你当前版本到最新版本之间”的变化，其他历史版本可以先跳过。</p><p>打开 README，定位到 <strong>“版本演进 (Changelog)”</strong>，从最新版本开始往下看，直到看到你当前版本为止。</p><p><strong>你应该看到</strong>：版本按 <code>vX.Y.Z (YYYY-MM-DD)</code> 的格式列出，并且每个版本都有分组说明（如核心修复/功能增强）。</p><h3 id="第-4-步-升级后做一次最小验证" tabindex="-1">第 4 步：升级后做一次最小验证 <a class="header-anchor" href="#第-4-步-升级后做一次最小验证" aria-label="Permalink to &quot;第 4 步：升级后做一次最小验证&quot;">​</a></h3><p><strong>为什么</strong> 升级后的第一件事不是“跑复杂场景”，而是先确认代理还能正常启动、能被客户端探活。</p><p>按 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">启动本地反代并接入第一个客户端（/healthz + SDK 配置）</a></strong> 的流程，至少验证一次 <code>GET /healthz</code>。</p><p><strong>你应该看到</strong>：<code>/healthz</code> 返回成功（用于确认服务可用）。</p><h2 id="近期版本摘要-摘自-readme" tabindex="-1">近期版本摘要（摘自 README） <a class="header-anchor" href="#近期版本摘要-摘自-readme" aria-label="Permalink to &quot;近期版本摘要（摘自 README）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>版本</th><th>日期</th><th>你需要关注的点</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Thinking 中断与 0 Token 防御；移除 <code>gemini-2.5-flash-lite</code> 并提醒你手动替换自定义映射；语言/主题等设置即时生效；监控看板增强；OAuth 兼容性提升</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Windows 平台后台进程静默运行（修复控制台闪烁）</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>图片生成参数映射增强（<code>size</code>/<code>quality</code>）；Cloudflared 隧道支持；修复合并冲突导致的启动失败；三层渐进式上下文压缩</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">怎么快速判断“这次更新会不会影响我”</p><p>优先找这两类句子：</p><ul><li><strong>用户提醒/你需要修改</strong>：比如明确点名某个默认模型被移除，要求你手动调整自定义映射</li><li><strong>核心修复/兼容性修复</strong>：比如 0 Token、429、Windows 闪烁、启动失败这类“会让你用不了”的问题</li></ul></div><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>内容</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>README 内嵌 Changelog（版本演进）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>About 页展示版本号与“检查更新”按钮</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>About 页“检查更新”命令返回结构</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>自动更新通知（下载并重启）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>当前版本号（构建元数据）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const p=a(n,[["render",l]]);export{b as __pageData,p as default};
